import React, { useLayoutEffect, useState } from "react";
import { getActivityLogs } from "../../../../../api";
import { useSetRecoilState } from "recoil";
import { Notification } from "../../../../../modules/global/global-states";
import axios from "axios";

type activityInfo = {
  id: number;
  timestamp: string;
  tableName: string;
  recordId: string;
  action: string;
  valueBefore: string;
  valueAfter: string;
};

export function useActivityLogsTableHooks() {
  const setNotification = useSetRecoilState(Notification);
  const [activityData, setActivityData] = useState<activityInfo[]>([]);

  useLayoutEffect(() => {
    getActivityLogs()
      .then((res) => {
        setActivityData(res);
      })
      .catch((err) => {
        setNotification({
          title: "Error fetching Equipment Info Record data",
          message: JSON.stringify(err),
          level: 2,
        });
      });
  }, [setNotification]);

  return activityData;
}
